import { useRef, useState } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import { Button } from '@leafygreen-ui/button';
import Popconfirm from './index';

const meta = {
  component: Popconfirm,
  tags: ['ai-generated', 'needs-work'],
} satisfies Meta<typeof Popconfirm>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {
  render: (args) => {
    const [open, setOpen] = useState(false);
    const buttonRef = useRef<HTMLButtonElement>(null);
    return (
      <>
        <Button ref={buttonRef} onClick={() => setOpen(true)}>
          Delete Item
        </Button>
        <Popconfirm
          {...args}
          open={open}
          setOpen={setOpen}
          refEl={buttonRef}
        >
          Are you sure you want to delete this item?
        </Popconfirm>
      </>
    );
  },
  play: async ({ canvas, userEvent }) => {
    const trigger = canvas.getByRole('button', { name: /delete item/i });
    await userEvent.click(trigger);
    await expect(await canvas.findByRole('button', { name: /yes/i })).toBeVisible();
    await expect(canvas.getByRole('button', { name: /cancel/i })).toBeVisible();
  },
};

export const CustomConfirmText: Story = {
  render: (args) => {
    const [open, setOpen] = useState(false);
    const buttonRef = useRef<HTMLButtonElement>(null);
    return (
      <>
        <Button ref={buttonRef} onClick={() => setOpen(true)}>
          Trigger
        </Button>
        <Popconfirm
          {...args}
          open={open}
          setOpen={setOpen}
          refEl={buttonRef}
          confirmText="Confirm"
        >
          Proceed with this action?
        </Popconfirm>
      </>
    );
  },
};

