 1→import { useCallback } from "react";
 2→import {
 3→  RECENT_PAGE_SIZE_KEY,
 4→  PaginationQueryParams,
 5→} from "../../constants/pagination";
 6→import { getDefaultPageSize } from "../../utils/pagination";
 7→import { useQueryParam, useQueryParams } from "../useQueryParam";
 8→
 9→/**
10→ * `usePagination` is a hook that manages the page and page size query params
11→ * It also saves the page size to local storage so that it can be remembered between sessions
12→ * Updating the page size will reset the page to 0
13→ * @returns - an object containing the current page, page size limit, and functions to update the page and page limit
14→ */
15→const usePagination = () => {
16→  const [queryParams, setQueryParams] = useQueryParams();
17→  const [page, setPage] = useQueryParam(PaginationQueryParams.Page, 0);
18→  const [limit] = useQueryParam(
19→    PaginationQueryParams.Limit,
20→    getDefaultPageSize(),
21→  );
22→
23→  /**
24→   * `setLimit` updates the page size query param and saves the page size to local storage
25→   * @param pageSize - the new page size
26→   */
27→  const setLimit = useCallback(
28→    (pageSize: number) => {
29→      localStorage.setItem(RECENT_PAGE_SIZE_KEY, pageSize.toString());
30→      setQueryParams({
31→        ...queryParams,
32→        [PaginationQueryParams.Limit]: pageSize,
33→        [PaginationQueryParams.Page]: 0,
34→      });
35→    },
36→    [queryParams, setQueryParams],
37→  );
38→
39→  return { page, limit, setLimit, setPage };
40→};
41→
42→export default usePagination;
